ReportUtil = {}

function  ReportUtil.getPlayerLevelInterval()
    local level = GUIBedWarHallToolBar:getPlayerLevel()
    if level == 1 then
        return "1"
    elseif level == 2 then
        return "2"
    elseif level >= 3 and level <= 7 then
        return "3_7"
    elseif level >= 8 and level <= 15 then
        return "8_15"
    elseif level >= 16 then
        return "16"
    end
end

